<script setup>
import { ref, onMounted } from 'vue'
import { Switch, Plus, Delete, Bell } from '@element-plus/icons-vue'
import { getHabits, getReminderSettings, updateReminderSettings, addHabitReminder, removeHabitReminder } from '../services/storage.js'
import NotificationPermission from './NotificationPermission.vue'

// 提醒设置
const settings = ref({
  enabled: true,
  soundEnabled: true,
  vibrationEnabled: true
})

// 习惯列表
const habits = ref([])

// 新提醒时间
const newReminderTime = ref('')

// 编辑中的习惯
const editingHabit = ref(null)

// 加载数据
const loadData = async () => {
  // 加载提醒设置
  const loadedSettings = await getReminderSettings()
  settings.value = loadedSettings
  
  // 加载习惯列表
  const loadedHabits = await getHabits()
  habits.value = loadedHabits
}

// 更新提醒设置
const handleUpdateSettings = async () => {
  await updateReminderSettings(settings.value)
  console.log('[DEBUG] 提醒设置已保存:', settings.value)
}

// 设置编辑中的习惯
const setEditingHabit = (habit) => {
  editingHabit.value = habit
  newReminderTime.value = ''
}

// 添加提醒时间
const handleAddReminder = async () => {
  if (!editingHabit.value || !newReminderTime.value) return
  
  const success = await addHabitReminder(editingHabit.value.id, newReminderTime.value)
  if (success) {
    // 重新加载习惯数据
    await loadData()
    newReminderTime.value = ''
  }
}

// 移除提醒时间
const handleRemoveReminder = async (habitId, time) => {
  const success = await removeHabitReminder(habitId, time)
  if (success) {
    // 重新加载习惯数据
    await loadData()
  }
}

// 初始化
onMounted(async () => {
  await loadData()
})
</script>

<template>
  <div class="reminder-settings">
    <div class="settings-container">
      <h2 class="settings-title">
        <el-icon><Bell /></el-icon>
        提醒设置
      </h2>
      
      <!-- 权限管理 -->
      <div class="permission-section">
        <h3 class="section-title">通知权限</h3>
        <NotificationPermission />
      </div>
      
      <!-- 全局设置 -->
      <div class="global-settings">
        <h3 class="section-title">全局设置</h3>
        
        <el-card shadow="hover" class="settings-card">
          <el-form label-width="120px">
            <el-form-item label="启用提醒">
              <el-switch 
                v-model="settings.enabled" 
                @change="handleUpdateSettings"
                inline-prompt
                :active-text="'开启'"
                :inactive-text="'关闭'"
              />
            </el-form-item>
            
            <el-form-item label="声音提醒">
              <el-switch 
                v-model="settings.soundEnabled" 
                @change="handleUpdateSettings"
                inline-prompt
                :active-text="'开启'"
                :inactive-text="'关闭'"
                :disabled="!settings.enabled"
              />
            </el-form-item>
            
            <el-form-item label="震动提醒">
              <el-switch 
                v-model="settings.vibrationEnabled" 
                @change="handleUpdateSettings"
                inline-prompt
                :active-text="'开启'"
                :inactive-text="'关闭'"
                :disabled="!settings.enabled"
              />
            </el-form-item>
          </el-form>
        </el-card>
      </div>
      
      <!-- 习惯提醒设置 -->
      <div class="habit-reminders">
        <h3 class="section-title">习惯提醒</h3>
        
        <div class="habits-grid">
          <el-card 
            v-for="habit in habits" 
            :key="habit.id"
            shadow="hover"
            class="habit-card"
          >
            <div class="habit-header">
              <h4 class="habit-name">{{ habit.name }}</h4>
              <el-button
                type="primary"
                size="small"
                @click="setEditingHabit(habit)"
              >
                编辑提醒
              </el-button>
            </div>
            
            <div class="habit-reminders-list">
              <div 
                v-if="!habit.reminders || habit.reminders.length === 0"
                class="no-reminders"
              >
                暂无提醒时间
              </div>
              
              <div 
                v-else
                class="reminders-list"
              >
                <el-tag 
                  v-for="time in habit.reminders" 
                  :key="time"
                  closable
                  @close="handleRemoveReminder(habit.id, time)"
                  effect="dark"
                  type="primary"
                >
                  {{ time }}
                </el-tag>
              </div>
            </div>
          </el-card>
        </div>
      </div>
    </div>
    
    <!-- 编辑提醒对话框 -->
    <el-dialog
      v-model="editingHabit"
      :title="`编辑 ${editingHabit?.name} 的提醒`"
      width="500px"
      :close-on-click-modal="false"
    >
      <div class="dialog-content">
        <p class="habit-description">{{ editingHabit?.description }}</p>
        
        <div class="current-reminders">
          <h4>当前提醒时间</h4>
          <div class="reminders-list">
            <el-tag 
              v-if="editingHabit?.reminders && editingHabit.reminders.length > 0"
              v-for="time in editingHabit.reminders" 
              :key="time"
              effect="plain"
            >
              {{ time }}
            </el-tag>
            <span v-else class="no-reminders">暂无提醒时间</span>
          </div>
        </div>
        
        <div class="add-reminder">
          <h4>添加新提醒</h4>
          <div class="add-reminder-form">
            <el-time-picker
              v-model="newReminderTime"
              format="HH:mm"
              value-format="HH:mm"
              placeholder="选择时间"
              style="width: 120px; margin-right: 10px;"
            />
            <el-button
              type="primary"
              @click="handleAddReminder"
              :disabled="!newReminderTime"
            >
              <el-icon><Plus /></el-icon> 添加
            </el-button>
          </div>
        </div>
      </div>
      
      <template #footer>
        <span class="dialog-footer">
          <el-button @click="editingHabit = null">关闭</el-button>
        </span>
      </template>
    </el-dialog>
  </div>
</template>

